css:
* { margin: 0; padding: 0; box-sizing: border-box; }
body { font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; background: #fffbf5; color: #1c1917; }
header { background: white; border-bottom: 1px solid #fed7aa; position: sticky; top: 0; z-index: 100; }
nav { display: flex; align-items: center; justify-content: space-between; max-width: 1100px; margin: 0 auto; padding: 0 28px; height: 64px; }
.logo { font-size: 18px; font-weight: 800; color: #ea580c; white-space: nowrap; }
.links { display: flex; gap: 20px; } .links a { color: #78716c; text-decoration: none; font-size: 14px; font-weight: 500; } .links a:hover { color: #ea580c; }
.search { display: flex; align-items: center; } .search input { height: 36px; border-radius: 18px; border: 1px solid #fed7aa; background: #fff7ed; padding: 0 16px; font-size: 13px; outline: none; width: 160px; } input:focus { border-color: #ea580c; }
.hero { display: flex; justify-content: space-between; align-items: center; padding: 56px 48px; background: linear-gradient(135deg, #fff7ed, #fef3c7); max-width: 1100px; margin: 0 auto; }
.hero-tag { display: inline-block; color: #ea580c; font-size: 13px; font-weight: 700; letter-spacing: 2px; margin-bottom: 14px; }
h1 { font-size: 56px; font-weight: 900; line-height: 1; letter-spacing: -2px; margin-bottom: 14px; color: #1c1917; }
.recipe-meta { display: flex; gap: 14px; margin-bottom: 14px; }
.recipe-meta span { font-size: 14px; color: #78716c; font-weight: 500; }
.hero-content p { color: #78716c; font-size: 16px; line-height: 1.7; margin-bottom: 20px; max-width: 440px; }
.recipe-btn { padding: 14px 28px; border-radius: 30px; border: none; background: #ea580c; color: white; font-weight: 800; font-size: 15px; cursor: pointer; }
.hero-img { font-size: 120px; }
.categories { background: white; border-bottom: 1px solid #fed7aa; }
.cat-scroll { display: flex; gap: 8px; padding: 12px 48px; overflow-x: auto; max-width: 1100px; margin: 0 auto; }
.cat { padding: 10px 18px; border-radius: 20px; border: 1px solid #fed7aa; background: transparent; font-size: 14px; font-weight: 600; cursor: pointer; white-space: nowrap; transition: all 0.2s; color: #78716c; } .cat:hover, .cat.active { background: #ea580c; border-color: #ea580c; color: white; }
.recipes { padding: 40px 48px; max-width: 1100px; margin: 0 auto; }
.recipes h2 { font-size: 26px; font-weight: 800; margin-bottom: 24px; }
.recipes-grid { display: grid; grid-template-columns: repeat(auto-fill, minmax(260px, 1fr)); gap: 20px; }
.recipe-card { background: white; border-radius: 18px; overflow: hidden; border: 1px solid #fed7aa; transition: all 0.2s; cursor: pointer; } .recipe-card:hover { transform: translateY(-4px); box-shadow: 0 12px 28px rgba(234,88,12,0.1); }
.rc-img { height: 180px; display: flex; align-items: center; justify-content: center; font-size: 72px; }
.rc-info { padding: 16px; } .rc-cat { font-size: 11px; font-weight: 700; color: #ea580c; letter-spacing: 1px; margin-bottom: 6px; } .rc-name { font-size: 16px; font-weight: 700; margin-bottom: 8px; line-height: 1.3; } .rc-meta { display: flex; gap: 12px; font-size: 12px; color: #9ca3af; margin-bottom: 12px; } .rc-rating { display: flex; align-items: center; gap: 4px; font-size: 13px; font-weight: 700; color: #ea580c; }
.newsletter { background: linear-gradient(135deg, #ea580c, #dc2626); }
.nl-content { max-width: 600px; margin: 0 auto; padding: 60px 28px; text-align: center; color: white; }
.nl-emoji { font-size: 48px; margin-bottom: 16px; }
.nl-content h3 { font-size: 28px; font-weight: 800; margin-bottom: 10px; } .nl-content p { color: rgba(255,255,255,0.8); margin-bottom: 24px; }
.nl-form { display: flex; gap: 10px; max-width: 400px; margin: 0 auto; }
.nl-form input { flex: 1; height: 48px; border-radius: 12px; border: none; background: rgba(255,255,255,0.2); color: white; padding: 0 16px; font-size: 14px; outline: none; } input::placeholder { color: rgba(255,255,255,0.6); }
.nl-form button { height: 48px; padding: 0 22px; border-radius: 12px; border: none; background: white; color: #ea580c; font-weight: 800; cursor: pointer; white-space: nowrap; }

