const recipes = [
  {name:'Ev Yapımı Tiramisu',cat:'tatli',catLabel:'TATLI',emoji:'🍮',time:'45 dk',serving:'4 kişi',rating:'4.9',likes:'1.2K',bg:'#fef3c7,#fde68a'},
  {name:'Kremali Mantarlı Makarna',cat:'ana',catLabel:'ANA YEMEK',emoji:'🍝',time:'30 dk',serving:'2 kişi',rating:'4.8',likes:'890',bg:'#fef2f2,#fecaca'},
  {name:'Yunan Salatası',cat:'salata',catLabel:'SALATA',emoji:'🥗',time:'15 dk',serving:'3 kişi',rating:'4.7',likes:'654',bg:'#f0fdf4,#bbf7d0'},
  {name:'Mercimek Çorbası',cat:'corba',catLabel:'ÇORBA',emoji:'🍲',time:'40 dk',serving:'6 kişi',rating:'4.9',likes:'2.1K',bg:'#fff7ed,#fed7aa'},
  {name:'Fransız Kruasanı',cat:'kahvalti',catLabel:'KAHVALTI',emoji:'🥐',time:'90 dk',serving:'8 kişi',rating:'4.6',likes:'445',bg:'#fefce8,#fef08a'},
  {name:'Çikolatalı Sufle',cat:'tatli',catLabel:'TATLI',emoji:'🍫',time:'25 dk',serving:'2 kişi',rating:'5.0',likes:'3.4K',bg:'#1c1917,#292524'}
];
let currentCat = 'all';
function renderRecipes() {
  const visible = currentCat === 'all' ? recipes : recipes.filter(r => r.cat === currentCat);
  document.getElementById('recipes-grid').innerHTML = visible.map(r => `
    <div class='recipe-card'>
      <div class='rc-img' style='background:linear-gradient(135deg,${r.bg})'>${r.emoji}</div>
      <div class='rc-info'>
        <div class='rc-cat'>${r.catLabel}</div>
        <div class='rc-name'>${r.name}</div>
        <div class='rc-meta'><span>⏱ ${r.time}</span><span>👥 ${r.serving}</span></div>
        <div class='rc-rating'>★ ${r.rating} <span style='color:#9ca3af;font-weight:400'>· ${r.likes} beğeni</span></div>
      </div>
    </div>
  `).join('');
}
function filterCat(cat, btn) { currentCat = cat; document.querySelectorAll('.cat').forEach(b=>b.classList.remove('active')); btn.classList.add('active'); renderRecipes(); }
function subscribe() { const inp = document.querySelector('.nl-form input'); const btn = document.querySelector('.nl-form button'); if (inp.value.includes('@')) { btn.textContent='✓ Kaydedildi!'; btn.style.background='#22c55e'; inp.value=''; setTimeout(()=>{btn.textContent='Abone Ol';btn.style.background='white';},2500); } }
renderRecipes();
